import{_ as t,o,c as a,ai as s}from"./chunks/framework.EKiYdDTS.js";const u=JSON.parse('{"title":"The Agent Loop","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/agent-loop.md","filePath":"concepts/agent-loop.md","rawMarkdown":"# The Agent Loop\\n\\nThe agent loop is the core of ra. It\'s a simple cycle: send messages to a model, collect tool calls from the response, execute the tools, feed the results back, and repeat until the model has nothing left to do.\\n\\n```\\nUser message\\n  → Model generates a response\\n    → Response contains tool calls?\\n      → Yes: execute tools, feed results back → loop\\n      → No: done\\n```\\n\\nThat\'s it. Every agent built with ra follows this pattern.\\n\\n## How it works\\n\\nEach iteration of the loop does three things:\\n\\n1. **Call the model** — send the conversation history (system prompt + messages + tool results) to the LLM provider\\n2. **Stream the response** — tokens arrive one at a time via server-sent events\\n3. **Execute tool calls** — if the model requested tools, run them (in parallel by default) and append the results to the conversation\\n\\nThe loop continues until:\\n- The model responds with plain text and no tool calls (natural completion)\\n- `maxIterations` is reached\\n- `maxTokenBudget` or `maxDuration` is exceeded\\n- Middleware calls `stop()`\\n\\n## A concrete example\\n\\nWhen you run `ra \\"List the files in src/\\"`, here\'s what happens:\\n\\n1. ra sends your message to the model\\n2. The model responds with a `Bash` tool call: `ls src/`\\n3. ra executes the command and captures the output\\n4. The output goes back to the model\\n5. The model responds with a summary — no more tool calls\\n6. Loop ends, you see the result\\n\\nIf the model needed multiple steps (say, reading a file and then editing it), it would just keep requesting tools, and the loop would keep running.\\n\\n## Middleware hooks\\n\\nThe loop exposes hooks at every stage so you can observe or modify behavior without changing the core:\\n\\n| Hook | When it fires |\\n|------|---------------|\\n| `beforeLoopBegin` | Once, before the first iteration |\\n| `beforeModelCall` | Before each LLM call (can modify messages and tools) |\\n| `onStreamChunk` | For each streaming token |\\n| `afterModelResponse` | After the model finishes responding |\\n| `beforeToolExecution` | Before each tool runs (can deny execution) |\\n| `afterToolExecution` | After each tool completes |\\n| `afterLoopIteration` | After each full iteration |\\n| `afterLoopComplete` | Once, when the loop ends |\\n| `onError` | When an error occurs |\\n\\nSee [Middleware](/middleware/) for details on writing hooks.\\n\\n## Parallel tool calls\\n\\nWhen the model requests multiple tools in a single response, ra executes them concurrently by default. This means an agent that needs to read three files doesn\'t wait for each one sequentially — it reads all three at once.\\n\\nDisable this with `parallelToolCalls: false` in your config if you need sequential execution.\\n\\n## Configuration\\n\\n```yaml\\nagent:\\n  maxIterations: 50        # 0 = unlimited\\n  maxTokenBudget: 500000   # 0 = unlimited\\n  maxDuration: 300000      # 5 minutes, in ms\\n  parallelToolCalls: true  # default\\n```\\n\\nSee [The Agent Loop reference](/core/agent-loop) for the full specification.\\n"}'),n={name:"concepts/agent-loop.md"};function l(i,e,r,d,h,p){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="the-agent-loop" tabindex="-1">The Agent Loop <a class="header-anchor" href="#the-agent-loop" aria-label="Permalink to &quot;The Agent Loop&quot;">​</a></h1><p>The agent loop is the core of ra. It&#39;s a simple cycle: send messages to a model, collect tool calls from the response, execute the tools, feed the results back, and repeat until the model has nothing left to do.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User message</span></span>
<span class="line"><span>  → Model generates a response</span></span>
<span class="line"><span>    → Response contains tool calls?</span></span>
<span class="line"><span>      → Yes: execute tools, feed results back → loop</span></span>
<span class="line"><span>      → No: done</span></span></code></pre></div><p>That&#39;s it. Every agent built with ra follows this pattern.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>Each iteration of the loop does three things:</p><ol><li><strong>Call the model</strong> — send the conversation history (system prompt + messages + tool results) to the LLM provider</li><li><strong>Stream the response</strong> — tokens arrive one at a time via server-sent events</li><li><strong>Execute tool calls</strong> — if the model requested tools, run them (in parallel by default) and append the results to the conversation</li></ol><p>The loop continues until:</p><ul><li>The model responds with plain text and no tool calls (natural completion)</li><li><code>maxIterations</code> is reached</li><li><code>maxTokenBudget</code> or <code>maxDuration</code> is exceeded</li><li>Middleware calls <code>stop()</code></li></ul><h2 id="a-concrete-example" tabindex="-1">A concrete example <a class="header-anchor" href="#a-concrete-example" aria-label="Permalink to &quot;A concrete example&quot;">​</a></h2><p>When you run <code>ra &quot;List the files in src/&quot;</code>, here&#39;s what happens:</p><ol><li>ra sends your message to the model</li><li>The model responds with a <code>Bash</code> tool call: <code>ls src/</code></li><li>ra executes the command and captures the output</li><li>The output goes back to the model</li><li>The model responds with a summary — no more tool calls</li><li>Loop ends, you see the result</li></ol><p>If the model needed multiple steps (say, reading a file and then editing it), it would just keep requesting tools, and the loop would keep running.</p><h2 id="middleware-hooks" tabindex="-1">Middleware hooks <a class="header-anchor" href="#middleware-hooks" aria-label="Permalink to &quot;Middleware hooks&quot;">​</a></h2><p>The loop exposes hooks at every stage so you can observe or modify behavior without changing the core:</p><table tabindex="0"><thead><tr><th>Hook</th><th>When it fires</th></tr></thead><tbody><tr><td><code>beforeLoopBegin</code></td><td>Once, before the first iteration</td></tr><tr><td><code>beforeModelCall</code></td><td>Before each LLM call (can modify messages and tools)</td></tr><tr><td><code>onStreamChunk</code></td><td>For each streaming token</td></tr><tr><td><code>afterModelResponse</code></td><td>After the model finishes responding</td></tr><tr><td><code>beforeToolExecution</code></td><td>Before each tool runs (can deny execution)</td></tr><tr><td><code>afterToolExecution</code></td><td>After each tool completes</td></tr><tr><td><code>afterLoopIteration</code></td><td>After each full iteration</td></tr><tr><td><code>afterLoopComplete</code></td><td>Once, when the loop ends</td></tr><tr><td><code>onError</code></td><td>When an error occurs</td></tr></tbody></table><p>See <a href="/ra/middleware/">Middleware</a> for details on writing hooks.</p><h2 id="parallel-tool-calls" tabindex="-1">Parallel tool calls <a class="header-anchor" href="#parallel-tool-calls" aria-label="Permalink to &quot;Parallel tool calls&quot;">​</a></h2><p>When the model requests multiple tools in a single response, ra executes them concurrently by default. This means an agent that needs to read three files doesn&#39;t wait for each one sequentially — it reads all three at once.</p><p>Disable this with <code>parallelToolCalls: false</code> in your config if you need sequential execution.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">agent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  maxIterations</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">50</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 0 = unlimited</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  maxTokenBudget</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">500000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 0 = unlimited</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  maxDuration</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">300000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 5 minutes, in ms</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  parallelToolCalls</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # default</span></span></code></pre></div><p>See <a href="/ra/core/agent-loop.html">The Agent Loop reference</a> for the full specification.</p>`,23)])])}const m=t(n,[["render",l]]);export{u as __pageData,m as default};
